/* ─── STORM SCORE ENGINE ────────────────────────────────────────────────────── */
const PILL_WEIGHT = { active: 1.0, emerging: 0.6, fading: 0.25 };

function calcStormScores(pills) {
  const scoreOneSide = (ps) => {
    if (!ps.length) return 0;
    const uniqueCats = new Set(ps.map(p => p.cat)).size;
    const diversityMult = 1 + (uniqueCats - 1) * 0.28;
    const base = ps.reduce((s, p) => s + (PILL_WEIGHT[p.effectiveState ?? p.state] ?? 0.5), 0);
    return Math.min(100, Math.round(base * diversityMult * 12));
  };
  const riskScore = scoreOneSide(pills.filter(p => p.dir === "risk"));
  const oppScore  = scoreOneSide(pills.filter(p => p.dir === "opp"));
  const tensionBonus = (riskScore > 25 && oppScore > 25)
    ? Math.round(Math.min(riskScore, oppScore) * 0.2) : 0;
  return { riskScore, oppScore, stormScore: riskScore + oppScore + tensionBonus };
}

// ── Category auto-correction ──────────────────────────────────────────────────
// Systematically reclassifies GEO pills that describe financial/operational
// performance metrics as MACRO. The distinction:
//   GEO  = physical disruption to geography: supply chain blocked, route closed,
//           region inaccessible, sanctions restricting physical access.
//   MACRO= financial performance that happens to be reported by geography:
//           revenue, demand, sales, market share, consumer spend by country.
// This runs on every stock's pills at startup — covers all 9 known instances
// and any new ones added in future without manual per-pill edits.
const GEO_TO_MACRO_TRIGGERS = /revenue|sales|demand|growth|spending|consumer|volume|market.?share|deflation|contraction|decline|slowdown|slump|plateau|earnings|eps|ebitda|margin|profit/i;

function normalizePillCategories(pills) {
  return pills.map(p =>
    (p.cat === 'GEO' && GEO_TO_MACRO_TRIGGERS.test(p.label))
      ? { ...p, cat: 'MACRO' }
      : p
  );
}

/* ─── MOBILE DETECTION ──────────────────────────────────────────────────────── */
const MobileCtx = createContext(false);

function useMobile() {
  const [isMobile, setIsMobile] = useState(() => window.innerWidth < 768);
  useEffect(() => {
    const mq = window.matchMedia("(max-width: 767px)");
    const handler = (e) => setIsMobile(e.matches);
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, []);
  return isMobile;
}

/* ─── SWIPE PANEL CONTAINER — used by FeedView and CardsView on mobile ──────── */
function SwipePanels({ panels, labels, accentColor }) {
  const [active, setActive] = useState(0);
  const C = useContext(ThemeCtx);
  const acc = accentColor || C.accent;
  const touchX = useRef(null);

  const onTouchStart = (e) => { touchX.current = e.touches[0].clientX; };
  const onTouchEnd = (e) => {
    if (touchX.current === null) return;
    const dx = e.changedTouches[0].clientX - touchX.current;
    touchX.current = null;
    if (Math.abs(dx) < 40) return;
    if (dx < 0 && active < panels.length - 1) setActive(a => a + 1);
    if (dx > 0 && active > 0) setActive(a => a - 1);
  };

  return (
    <div style={{flex:1, display:"flex", flexDirection:"column", overflow:"hidden"}}>
      {/* Tab strip */}
      <div style={{display:"flex", borderBottom:`1px solid ${C.border}`, flexShrink:0, background:C.navLeft}}>
        {labels.map((lbl, i) => (
          <button key={i} onClick={() => setActive(i)} style={{
            flex:1, padding:"8px 4px", fontFamily:C.mono, fontSize:10, fontWeight:700,
            letterSpacing:"0.08em", border:"none", background:"transparent", cursor:"pointer",
            color: active === i ? acc : C.textDim,
            borderBottom:`2px solid ${active === i ? acc : "transparent"}`,
          }}>{lbl}</button>
        ))}
      </div>
      {/* Swipe track */}
      <div style={{flex:1, overflow:"hidden", position:"relative"}}
        onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}>
        <div style={{
          display:"flex", height:"100%",
          transform:`translateX(${-active * 100}%)`,
          transition:"transform 0.3s ease",
        }}>
          {panels.map((panel, i) => (
            <div key={i} style={{minWidth:"100%", height:"100%", overflow:"hidden", display:"flex", flexDirection:"column"}}>
              {panel}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

