// Fast O(1) lookup — used by Pill to distinguish live (RSS-backed) vs curated signals
const SIGNAL_RULES_LABEL_SET = new Set(SIGNAL_RULES.map(r => r.label));

/* ─── PILL TEMPORAL AGING ────────────────────────────────────────────────────
   Curated/static pills (○) carry editorial state (active / emerging / fading).
   That state is NEVER auto-changed by time — only by a human or Claude review.
   Live RSS-backed pills (●) are refreshed by the signal engine and never age.

   Freshness model:
     effectiveState  = pill.state  (always — no automatic downgrade)
     needsReview     = true when daysSinceReview >= PILL_REVIEW_DAYS (visual only)
     TTL_EXPIRED     = 180d safety-net — if a pill has genuinely gone unchecked
                       for 6 months it is retired from scoring entirely.

   Review freshness clock (priority chain):
     1. pill.lastChecked  — explicitly set by reviewer each refresh session
     2. pill.dateAdded    — used when pill has never been manually reviewed
     3. null              — no date = unreviewed → needsReview immediately (Infinity days)

   Pills with NO date are flagged for review immediately. They are NOT expired —
   expiry only applies to pills with a known base date that is >= TTL_EXPIRED days old.
─────────────────────────────────────────────────────────────────────────────── */
const PILL_REVIEW_DAYS  = 30;  // days since lastChecked → show needs-review indicator (visual only)
const TTL_EXPIRED       = 180; // days since lastChecked → safety-net expiry, excluded from scores

function agePill(pill) {
  // Live RSS-backed pills, auto-generated social pills, and short-interest pills are always current
  if (SIGNAL_RULES_LABEL_SET.has(pill.label) || pill.autoSocial || pill.autoShortInterest) {
    return { ...pill, effectiveState: pill.state, daysSinceReview: 0, needsReview: false };
  }

  // Use the most recent review signal available. No date = unreviewed.
  const base            = pill.lastChecked ? new Date(pill.lastChecked)
                        : pill.dateAdded   ? new Date(pill.dateAdded)
                        : null;
  const daysSinceReview = base
                        ? Math.max(0, Math.floor((Date.now() - base.getTime()) / 86400000))
                        : Infinity;

  // State is EDITORIAL — never auto-changed. TTL_EXPIRED only fires when we have a dated base.
  const effectiveState  = (base && daysSinceReview >= TTL_EXPIRED) ? "expired" : pill.state;

  return {
    ...pill,
    effectiveState,
    daysSinceReview,
    needsReview: !base || daysSinceReview >= PILL_REVIEW_DAYS,
  };
}

