/* ─── ARTICLE MATCHING — three-tier relevance system ────────────────────────
  Tier 1 — EXACT: article signal fires on this pill label + ticker  (current behavior)
  Tier 2 — SEMANTIC: keyword extraction from pill label scored against live articles
  Tier 3 — CACHED API: /api/pill-articles fetch for truly fresh, ticker-specific news

  Tier 1 covers live RSS pills (●). Tiers 2+3 cover curated static pills (○).
  Results are deduplicated and capped at 5.
─────────────────────────────────────────────────────────────────────────────── */
const STOP_WORDS = new Set([
  "the","a","an","of","in","for","to","and","or","at","by","as","is","on","with",
  "from","are","has","been","its","that","this","will","can","was","be","we","all",
  "they","our","not","also","into","but","about","than","while","after","before",
  "over","under","through","up","down","between","per","vs","via","amid","amid",
]);

// Category-specific boost words: articles matching these terms score higher for each cat
const CAT_BOOST = {
  GPOL:   ["export","control","sanction","military","defense","geopolit","conflict","war","iran","taiwan","china","russia","nato"],
  MACRO:  ["inflation","recession","fed","gdp","economy","interest","rate","fiscal","monetary","yield","deficit"],
  WEATHER:["drought","flood","hurricane","climate","storm","crop","harvest","el niño","weather","wildfire"],
  RATE:   ["federal reserve","fomc","interest rate","yield","rate cut","rate hike","monetary","treasury","bps"],
  SECT:   [],  // fully keyword-driven for sector pills
  GEO:    ["china","europe","asia","japan","india","brazil","emerging","regional","border","supply chain"],
  POL:    ["regulation","legislation","congress","antitrust","doj","ftc","sec","senate","house","law","rule"],
  EARN:   ["earnings","revenue","margin","profit","quarterly","guidance","eps","beat","miss","outlook"],
  SUPPLY: ["supply","chain","shortage","inventory","logistics","capacity","bottleneck","delay","disruption"],
  TECH:   ["technology","ai","artificial intelligence","software","platform","cloud","data","compute","chip"],
  CLMT:   ["carbon","emissions","climate","esg","offset","renewable","net zero","sustainability"],
  GEOP:   ["geopolitical","global","international","foreign","trade","currency","fx","dollar","exchange"],
};

function extractKeywords(pill) {
  const desc = pill.label.includes(":")
    ? pill.label.split(":").slice(1).join(":").trim()
    : pill.label;
  return desc
    .replace(/[$%×+\-]/g, " ")
    .split(/[\s/().,"']+/)
    .map(w => w.replace(/[^a-zA-Z0-9]/g, "").toLowerCase())
    .filter(w => w.length >= 3 && !STOP_WORDS.has(w));
}

function scoreArticle(item, keywords, boosts, ticker) {
  const text = [
    item.headline ?? "",
    item.body ?? "",
    (item.signals ?? []).map(s => s.ticker + " " + (s.label ?? "")).join(" "),
  ].join(" ").toLowerCase();

  // Ticker match: strong positive signal
  const tickerHit = ticker && (
    text.includes(ticker.toLowerCase()) ||
    (item.signals ?? []).some(s => s.ticker === ticker)
  );
  let score = tickerHit ? 4 : 0;

  for (const kw of keywords) if (text.includes(kw)) score += 1.5;
  for (const bk of boosts)   if (text.includes(bk)) score += 0.6;

  return score;
}

// Cache for /api/pill-articles results: ticker+label → { ts, articles }
const _pillArticleCache = new Map();

// Returns live articles that best support a given pill for a given ticker.
// Tier 1 (exact signal match) is tried first; if ≥ 2 found, returned immediately.
// Otherwise Tier 2 (semantic scoring) re-ranks all live articles.
// Tier 3 (/api/pill-articles) fires asynchronously when Tier 2 yields < 2 results
// and the result is stored in _pillArticleCache for subsequent renders.
function articlesForPill(pill, liveArticles, ticker, onFetched) {
  if (!liveArticles?.length && !onFetched) return [];

  // ── Tier 1: exact signal label match ─────────────────────────────────────
  const exact = (liveArticles ?? []).filter(item =>
    Array.isArray(item.signals) &&
    item.signals.some(s => s.label === pill.label && (!ticker || s.ticker === ticker))
  );
  if (exact.length >= 2) return exact.slice(0, 5);

  // ── Tier 2: semantic keyword scoring over all live articles ───────────────
  const keywords = extractKeywords(pill);
  const boosts   = CAT_BOOST[pill.cat] ?? [];
  const semantic = (liveArticles ?? [])
    .filter(item => item.headline)
    .map(item => ({ item, score: scoreArticle(item, keywords, boosts, ticker) }))
    .filter(({ score }) => score >= 1.5)
    .sort((a, b) => b.score - a.score)
    .slice(0, 5)
    .map(({ item }) => item);

  const combined = [...exact, ...semantic.filter(a => !exact.includes(a))].slice(0, 5);

  // ── Tier 3: /api/pill-articles — async fetch, result surfaced on next render
  if (combined.length < 2 && onFetched && ticker) {
    const cacheKey = `${ticker}|${pill.label}`;
    const cached   = _pillArticleCache.get(cacheKey);
    if (cached) {
      // Cache hit — return immediately
      return [...combined, ...cached.filter(a => !combined.find(c => c.headline === a.headline))].slice(0, 5);
    }
    // Not yet fetched — trigger async fetch (component will re-render via onFetched)
    _pillArticleCache.set(cacheKey, null); // sentinel: fetch in-flight
    const q = encodeURIComponent(`${ticker} ${keywords.slice(0, 4).join(" ")}`);
    fetch(`/api/pill-articles?ticker=${ticker}&q=${q}`)
      .then(r => r.ok ? r.json() : null)
      .then(data => {
        if (data?.articles?.length) {
          _pillArticleCache.set(cacheKey, data.articles);
          onFetched(data.articles); // triggers re-render in PillCard
        } else {
          _pillArticleCache.delete(cacheKey); // allow retry
        }
      })
      .catch(() => _pillArticleCache.delete(cacheKey));
  }

  return combined;
}

// Returns the lineage record for a pill+ticker pair — ruleText + causalLink.
// Returns null if no lineage data exists for this rule (graceful fallback).
function getLineageForPill(pill, ticker) {
  const rule = SIGNAL_RULES.find(r => r.label === pill.label);
  if (!rule) return null;
  const lineage = SIGNAL_LINEAGE[rule.id];
  if (!lineage) return null;
  return {
    ruleId:     rule.id,
    ruleText:   lineage.ruleText,
    causalLink: lineage.causalLinks?.[ticker] ?? null,
  };
}

// Returns the CSS color for the CornerArrow next to an article, based on which
// pill direction(s) the article supports. Risk=red, Opp=green, both=amber, none=accent.
// liveFeedItems carry: signals: [{ dir, cat, label, ticker }, ...]
// We compare signal labels directly against the pills' labels — no rule ID lookup needed.
function articlePillColor(item, pills, C) {
  if (!Array.isArray(item?.signals) || item.signals.length === 0) return C.accent;
  const sigLabels  = new Set(item.signals.map(s => s.label));
  const riskLabels = new Set(pills.filter(p => p.dir === "risk").map(p => p.label));
  const oppLabels  = new Set(pills.filter(p => p.dir === "opp" ).map(p => p.label));
  const hasRisk = [...sigLabels].some(l => riskLabels.has(l));
  const hasOpp  = [...sigLabels].some(l => oppLabels.has(l));
  if (hasRisk && hasOpp) return C.warn ?? "#F59E0B";
  if (hasRisk) return C.risk;
  if (hasOpp)  return C.opp;
  return C.accent;
}

