/* ─── FLAG IMAGE COMPONENT ───────────────────────────────────────────────────── */
// Local SVG flags served from public/flags/ — no CDN dependency, works offline.
function FlagImg({ code, size = 22 }) {
  return <img src={`/flags/${code}.svg`}
    alt={code.toUpperCase()} width={size * 1.5} height={size}
    style={{flexShrink:0, objectFit:"contain", borderRadius:2, verticalAlign:"middle"}}
    onError={e => { e.target.style.display = "none"; }} />;
}

