  showSectorLabels = true, setShowSectorLabels = ()=>{},
  showRiskTitles = true,   setShowRiskTitles = ()=>{},
  showOppTitles = true,    setShowOppTitles = ()=>{},
  gridMode = false,
  clusterPad = 12,         setClusterPad = ()=>{},
  boundedLayout = true,    setBoundedLayout = ()=>{},
